import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useToolAccess } from '../hooks/useToolAccess';
import { useGeminiGeneration } from '../hooks/useGeminiGeneration';
import { useDocumentHead } from '../hooks/useDocumentHead';
import { useToast } from '../components/ui/Toast';
import { TOOL_PREVIEWS, TOOL_TIERS } from '../config/toolConfig';
import UpgradeModal from '../components/ui/UpgradeModal';
import { getToolSystemPrompt } from '../config/tools/toolPrompts';
import JsonLd, { toolJsonLd, breadcrumbJsonLd } from '../components/seo/JsonLd';

export default function ToolPage() {
  const { slug = '' } = useParams<{ slug: string }>();
  const { user, isLoading: authLoading } = useAuth();
  const { checkAccess, incrementUsage, getPreview, getTier } = useToolAccess();
  const { generate, isGenerating } = useGeminiGeneration();
  const { showToast } = useToast();
  const navigate = useNavigate();

  const [accessChecked, setAccessChecked] = useState(false);
  const [showUpgrade, setShowUpgrade] = useState(false);
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [result, setResult] = useState<string | null>(null);

  const preview = getPreview(slug);
  const tier = getTier(slug);

  useDocumentHead({
    title: preview?.name || 'AI Tool',
    description: preview?.desc,
    canonical: `https://tailormeswiftly.com/tools/${slug}`,
  });

  useEffect(() => {
    if (authLoading) return;

    async function check() {
      const { allowed, reason } = await checkAccess(slug);
      if (!allowed) {
        if (reason === 'not_authenticated') {
          navigate('/login');
          return;
        }
        setShowUpgrade(true);
      }
      setAccessChecked(true);
    }
    check();
  }, [slug, authLoading, checkAccess, navigate]);

  const handleGenerate = useCallback(async () => {
    const systemPrompt = getToolSystemPrompt(slug);
    const userPrompt = Object.entries(inputs)
      .filter(([, v]) => v.trim())
      .map(([k, v]) => `${k}: ${v}`)
      .join('\n\n');

    if (!userPrompt.trim()) {
      showToast('Please fill in the required fields.', true);
      return;
    }

    const res = await generate({ systemPrompt, userPrompt });
    if (res) {
      setResult(res.resumeHtml || res.rawText);
      await incrementUsage(slug);
    }
  }, [slug, inputs, generate, incrementUsage, showToast]);

  if (!accessChecked || authLoading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: '4rem', color: 'var(--text-secondary)' }}>
        <i className="fa-solid fa-spinner fa-spin" style={{ marginRight: '0.5rem' }} />
        Loading...
      </div>
    );
  }

  if (!preview) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem' }}>
        <h2 style={{ color: 'var(--text-primary)' }}>Tool not found</h2>
        <p style={{ color: 'var(--text-secondary)' }}>The tool "{slug}" doesn't exist.</p>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      <JsonLd data={toolJsonLd({ name: preview.name, desc: preview.desc, slug, tier: TOOL_TIERS[slug] || 'teaser' })} />
      <JsonLd data={breadcrumbJsonLd([
        { name: 'Home', url: 'https://tailormeswiftly.com/' },
        { name: 'Tools', url: 'https://tailormeswiftly.com/tools' },
        { name: preview.name, url: `https://tailormeswiftly.com/tools/${slug}` },
      ])} />
      {showUpgrade && (
        <UpgradeModal
          onClose={() => { setShowUpgrade(false); navigate('/dashboard'); }}
          toolPreview={preview}
        />
      )}

      {/* Tool Header */}
      <div style={{ marginBottom: '2rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.75rem' }}>
          <div style={{
            width: '48px',
            height: '48px',
            borderRadius: 'var(--brutal-radius)',
            background: 'var(--primary-color, #10b981)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '1.25rem',
            color: '#fff',
          }}>
            <i className={`fa-solid ${preview.icon}`} />
          </div>
          <div>
            <h1 style={{ margin: 0, fontSize: '1.5rem', color: 'var(--text-primary)' }}>
              {preview.name}
            </h1>
            {tier === 'teaser' && (
              <span style={{ fontSize: '0.75rem', color: '#f59e0b' }}>
                <i className="fa-solid fa-sparkles" /> Free trial
              </span>
            )}
          </div>
        </div>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.6, margin: 0 }}>
          {preview.desc}
        </p>
      </div>

      {/* Input Section */}
      {!result && (
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <ToolInputs slug={slug} inputs={inputs} setInputs={setInputs} />

          <button
            onClick={handleGenerate}
            disabled={isGenerating}
            className="btn secondary-btn large-action-btn"
          >
            {isGenerating ? (
              <><i className="fa-solid fa-spinner fa-spin" /> Generating...</>
            ) : (
              <><i className="fa-solid fa-wand-magic-sparkles" /> Generate</>
            )}
          </button>
        </div>
      )}

      {/* Result Section */}
      {result && (
        <div>
          <div
            className="glass-panel"
            style={{ padding: '1.5rem', marginBottom: '1rem' }}
            dangerouslySetInnerHTML={{ __html: result }}
          />

          <div style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap' }}>
            <button
              onClick={() => {
                navigator.clipboard.writeText(result.replace(/<[^>]*>/g, ''));
                showToast('Copied to clipboard!');
              }}
              className="btn ghost-btn"
            >
              <i className="fa-solid fa-copy" /> Copy
            </button>
            <button
              onClick={() => { setResult(null); setInputs({}); }}
              className="btn ghost-btn"
            >
              <i className="fa-solid fa-rotate" /> Try Again
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/** Dynamic input fields based on tool slug */
function ToolInputs({
  slug,
  inputs,
  setInputs,
}: {
  slug: string;
  inputs: Record<string, string>;
  setInputs: React.Dispatch<React.SetStateAction<Record<string, string>>>;
}) {
  const fields = getToolInputFields(slug);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
      {fields.map(field => (
        <div key={field.key}>
          <label style={{ display: 'block', marginBottom: '0.35rem', fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-secondary)' }}>
            {field.label}
            {field.required && <span style={{ color: '#ef4444' }}> *</span>}
          </label>
          {field.type === 'textarea' ? (
            <textarea
              value={inputs[field.key] || ''}
              onChange={e => setInputs(prev => ({ ...prev, [field.key]: e.target.value }))}
              placeholder={field.placeholder}
              rows={5}
            />
          ) : (
            <input
              type={field.type}
              value={inputs[field.key] || ''}
              onChange={e => setInputs(prev => ({ ...prev, [field.key]: e.target.value }))}
              placeholder={field.placeholder}
            />
          )}
        </div>
      ))}
    </div>
  );
}

interface FieldDef {
  key: string;
  label: string;
  type: 'text' | 'textarea';
  placeholder: string;
  required: boolean;
}

function getToolInputFields(slug: string): FieldDef[] {
  const resumeField: FieldDef = { key: 'resume', label: 'Your Resume', type: 'textarea', placeholder: 'Paste your resume text here...', required: true };
  const jobField: FieldDef = { key: 'jobDescription', label: 'Job Description', type: 'textarea', placeholder: 'Paste the job description here...', required: true };
  const companyField: FieldDef = { key: 'company', label: 'Target Company', type: 'text', placeholder: 'e.g., Google, Meta...', required: true };
  const roleField: FieldDef = { key: 'role', label: 'Target Role', type: 'text', placeholder: 'e.g., Senior Software Engineer', required: true };

  const fieldMap: Record<string, FieldDef[]> = {
    'cover-letter': [resumeField, jobField, companyField, { key: 'tone', label: 'Tone', type: 'text', placeholder: 'e.g., Professional, Conversational', required: false }],
    'pain-letter': [companyField, roleField, { key: 'research', label: 'Company Pain Points / Challenges', type: 'textarea', placeholder: 'What challenges is this company facing?', required: false }],
    'hook-generator': [roleField, companyField, { key: 'context', label: 'Context (cold email, cover letter, LinkedIn)', type: 'text', placeholder: 'Where will you use this hook?', required: true }],
    outreach: [resumeField, companyField, roleField, { key: 'contact', label: 'Contact Name/Title', type: 'text', placeholder: 'e.g., Jane Smith, VP Engineering', required: false }],
    'interview-prep': [resumeField, jobField, companyField],
    'salary-negotiator': [roleField, companyField, { key: 'currentSalary', label: 'Current/Expected Salary', type: 'text', placeholder: 'e.g., $120,000', required: true }, { key: 'offerDetails', label: 'Offer Details', type: 'textarea', placeholder: 'Base salary, equity, benefits...', required: false }],
    'toxic-radar': [companyField, roleField],
    'comp-decoder': [companyField, roleField, { key: 'offerDetails', label: 'Full Compensation Package', type: 'textarea', placeholder: 'Base, equity, bonus, benefits, PTO...', required: true }],
    'shadow-jobs': [companyField, roleField, { key: 'skills', label: 'Your Key Skills', type: 'textarea', placeholder: 'List your main skills...', required: true }],
    'guerrilla-tactics': [resumeField, jobField, companyField],
    'referral-mapper': [companyField, roleField, { key: 'network', label: 'Your Network/LinkedIn Connections', type: 'textarea', placeholder: 'Describe your professional network...', required: false }],
    'auto-app': [resumeField, { key: 'preferences', label: 'Job Preferences', type: 'textarea', placeholder: 'Desired roles, locations, salary range, remote preference...', required: true }],
    'thank-you': [companyField, roleField, { key: 'interviewNotes', label: 'Interview Notes', type: 'textarea', placeholder: 'Key topics discussed, interviewer names...', required: true }],
    'ghosting-predictor': [companyField, roleField, { key: 'listingUrl', label: 'Job Listing URL', type: 'text', placeholder: 'https://...', required: false }, { key: 'daysPosted', label: 'Days Since Posted', type: 'text', placeholder: 'e.g., 30', required: false }],
    'video-intro': [resumeField, roleField, companyField],
    'skills-tracker': [{ key: 'skills', label: 'Your Skills', type: 'textarea', placeholder: 'List your skills, one per line...', required: true }, roleField],
    'day-in-life': [companyField, roleField],
    'reverse-interview': [companyField, roleField, { key: 'concerns', label: 'Your Concerns/Priorities', type: 'textarea', placeholder: 'Work-life balance, growth, culture...', required: false }],
    'rejection-reverser': [companyField, roleField, { key: 'rejectionContext', label: 'Rejection Context', type: 'textarea', placeholder: 'How were you rejected? Any feedback given?', required: true }],
    'prove-it': [{ key: 'bullets', label: 'Resume Bullets to Quantify', type: 'textarea', placeholder: 'Paste weak resume bullets, one per line...', required: true }],
    'tech-screen': [roleField, companyField, { key: 'techStack', label: 'Tech Stack', type: 'textarea', placeholder: 'Languages, frameworks, tools...', required: true }],
    'cold-email': [companyField, { key: 'contact', label: 'Contact Name/Title', type: 'text', placeholder: 'e.g., Jane Smith, VP Engineering', required: true }, resumeField],
    'career-pivot': [{ key: 'currentRole', label: 'Current Role/Industry', type: 'text', placeholder: 'e.g., Marketing Manager at a bank', required: true }, { key: 'targetRole', label: 'Target Role/Industry', type: 'text', placeholder: 'e.g., Product Manager in tech', required: true }, resumeField],
  };

  return fieldMap[slug] || [resumeField, jobField];
}
