import { useState, useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';
import { TOOL_TIERS, TOOL_PREVIEWS, type ToolTier, type ToolPreview } from '../config/toolConfig';

interface AccessResult {
  allowed: boolean;
  reason?: 'not_authenticated' | 'teaser_exhausted' | 'premium';
}

export function useToolAccess() {
  const { user, isPremium, supabase } = useAuth();
  const [checking, setChecking] = useState(false);

  const checkAccess = useCallback(async (slug: string): Promise<AccessResult> => {
    const tier: ToolTier = TOOL_TIERS[slug] || 'free';
    if (tier === 'free') return { allowed: true };

    if (!user) return { allowed: false, reason: 'not_authenticated' };
    if (isPremium) return { allowed: true };

    if (tier === 'premium') return { allowed: false, reason: 'premium' };

    if (tier === 'teaser') {
      setChecking(true);
      try {
        const { data: profile } = await supabase
          .from('user_profiles')
          .select('tool_usage')
          .eq('user_id', user.id)
          .maybeSingle();

        const usage = (profile?.tool_usage as Record<string, number>) || {};
        const count = usage[slug] || 0;
        if (count >= 1) return { allowed: false, reason: 'teaser_exhausted' };
        return { allowed: true };
      } finally {
        setChecking(false);
      }
    }

    return { allowed: true };
  }, [user, isPremium, supabase]);

  const incrementUsage = useCallback(async (slug: string) => {
    if (!user) return;

    const { data: profile } = await supabase
      .from('user_profiles')
      .select('tool_usage')
      .eq('user_id', user.id)
      .maybeSingle();

    const usage = (profile?.tool_usage as Record<string, number>) || {};
    usage[slug] = (usage[slug] || 0) + 1;

    await supabase
      .from('user_profiles')
      .update({ tool_usage: usage })
      .eq('user_id', user.id);
  }, [user, supabase]);

  const getPreview = useCallback((slug: string): ToolPreview | undefined => {
    return TOOL_PREVIEWS[slug];
  }, []);

  const getTier = useCallback((slug: string): ToolTier => {
    return TOOL_TIERS[slug] || 'free';
  }, []);

  return { checkAccess, incrementUsage, getPreview, getTier, checking };
}
