import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/SupabaseContext';
import { useToast } from './Toast';

interface ToolPreview {
  icon: string;
  name: string;
  desc: string;
}

interface UpgradeModalProps {
  onClose: () => void;
  toolPreview?: ToolPreview;
  title?: string;
}

export default function UpgradeModal({ onClose, toolPreview, title }: UpgradeModalProps) {
  const { invokeEdgeFunction, session } = useAuth();
  const { showToast } = useToast();
  const navigate = useNavigate();

  const displayTitle = title || (toolPreview ? `You've experienced ${toolPreview.name}` : 'Free Trial Used');

  async function handleCheckout() {
    if (!session) {
      showToast('Please sign in first.', true);
      return;
    }
    const { data, error } = await invokeEdgeFunction('create-checkout', {
      returnUrl: window.location.origin + '/app/results',
    });
    if (error) {
      showToast(error.message, true);
      return;
    }
    const url = (data as Record<string, string>)?.url;
    if (url) window.location.href = url;
  }

  return (
    <div
      className="modal-overlay"
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div className="modal-dialog sm" style={{ textAlign: 'center' }}>
        <i className="fa-solid fa-crown" style={{ fontSize: '2.5rem', color: '#f59e0b', marginBottom: '1rem', display: 'block' }} />
        <h2 style={{ margin: '0 0 1rem', fontSize: '1.3rem', color: 'var(--text-primary)' }}>{displayTitle}</h2>

        {toolPreview && (
          <div
            className="glass-panel"
            style={{
              padding: '1rem',
              marginBottom: '1.25rem',
              textAlign: 'left',
              background: 'rgba(245,158,11,0.06)',
              borderColor: 'rgba(245,158,11,0.15)',
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginBottom: '0.5rem' }}>
              <i className={`fa-solid ${toolPreview.icon}`} style={{ color: '#f59e0b', fontSize: '1.1rem' }} />
              <strong style={{ color: 'var(--text-primary)', fontSize: '0.95rem' }}>{toolPreview.name}</strong>
            </div>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', lineHeight: 1.55, margin: 0 }}>{toolPreview.desc}</p>
          </div>
        )}

        <div style={{ textAlign: 'left', marginBottom: '1.25rem' }}>
          <p style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.5rem' }}>
            Go Pro and unlock:
          </p>
          {[
            'Unlimited resume tailoring',
            'All 26 AI tools, unlimited',
            'Daily news briefings + podcast',
            'Voice interviews & negotiation',
          ].map(text => (
            <span key={text} style={{ display: 'block', fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: '0.2rem' }}>
              <i className="fa-solid fa-check" style={{ color: '#10b981', marginRight: '0.4rem', fontSize: '0.7rem' }} />
              {text}
            </span>
          ))}
        </div>

        <button
          onClick={handleCheckout}
          className="btn secondary-btn large-action-btn"
          style={{ marginBottom: '0.75rem', background: 'linear-gradient(135deg, #f59e0b, #d97706)' }}
        >
          <i className="fa-solid fa-bolt" /> Go Pro — $9.99/mo
        </button>

        <button
          onClick={() => { onClose(); navigate('/dashboard'); }}
          className="btn ghost-btn large-action-btn"
        >
          Back to Dashboard
        </button>

        <Link
          to="/pricing"
          style={{
            display: 'block',
            marginTop: '0.75rem',
            fontSize: '0.8rem',
            color: 'var(--text-secondary)',
            textDecoration: 'none',
          }}
          onClick={onClose}
        >
          See full feature comparison &rarr;
        </Link>
      </div>
    </div>
  );
}
